//
// Use this to display billing warnings, gate features for unpaid accounts,
// or guide users toward resolving payment issues. Visible to every member
// of the organization regardless of role.
type OrganizationSubscriptionStatus string

const (
	// Free trial period. The organization has full access until the trial expires.
	OrganizationSubscriptionStatusTrial OrganizationSubscriptionStatus = "TRIAL"
	// Subscription is active and in good standing.
	OrganizationSubscriptionStatusActive OrganizationSubscriptionStatus = "ACTIVE"
	// A payment is overdue. Access continues but action is needed to avoid suspension.
	OrganizationSubscriptionStatusPastDue OrganizationSubscriptionStatus = "PAST_DUE"
	// The free trial has ended without a subscription. Functionality is limited.
	OrganizationSubscriptionStatusExpired OrganizationSubscriptionStatus = "EXPIRED"
	// The subscription was canceled. The organization is in a grace period.
	OrganizationSubscriptionStatusCanceled OrganizationSubscriptionStatus = "CANCELED"
	// The account is suspended due to billing issues. Most operations are blocked.
	OrganizationSubscriptionStatusSuspended OrganizationSubscriptionStatus = "SUSPENDED"
	// A payment is being processed. This is typically a brief transitional state.
	OrganizationSubscriptionStatusPaymentPending OrganizationSubscriptionStatus = "PAYMENT_PENDING"
	// The most recent payment attempt failed. Update payment details to restore access.
	OrganizationSubscriptionStatusPaymentFailed OrganizationSubscriptionStatus = "PAYMENT_FAILED"
)

var AllOrganizationSubscriptionStatus = []OrganizationSubscriptionStatus{
	OrganizationSubscriptionStatusTrial,
	OrganizationSubscriptionStatusActive,
	OrganizationSubscriptionStatusPastDue,
	OrganizationSubscriptionStatusExpired,
	OrganizationSubscriptionStatusCanceled,
	OrganizationSubscriptionStatusSuspended,
	OrganizationSubscriptionStatusPaymentPending,
	OrganizationSubscriptionStatusPaymentFailed,
}

